var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"SOLDIOR_FLOOR_RESEARCH_NULL","text":{"KOREA":"저희 프로젝트의 연구기지에 오신 걸 환영합니다, 프리하트 박사님.","JPN":"我がプロジェクトの研究基地へようこそ、プラハト博士。","ENG":"Welcome to our project research lab, Dr. Freeheart.","TWN":"歡迎來到我們專案的研究基地，普立哈特博士。"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":null,"C":{"char_id":"SOLDIOR_FLOOR_RESEARCH_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"안내해줘서 고맙습니다, 장교님.","JPN":"案内ありがとうございます、将校。","ENG":"Thank you for the tour, General.","TWN":"感謝你的介紹，長官。"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIOR_FLOOR_RESEARCH_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"깊은 심도의 이면세계에 이렇게 큰 시설을 지을 수 있다니. 경이롭군요.","JPN":"深い裏世界に、こんな大きな施設を建てられるとは。驚きました。","ENG":"It's amazing how such a large facility can be built in the depths of the Counterside.","TWN":"你們竟然能在深度異界裡建造如此龐大的設施，真是太不可思議了。"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIOR_FLOOR_RESEARCH_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SOLDIOR_FLOOR_RESEARCH_NULL","text":{"KOREA":"북방합의체의 기술력 덕분이죠. 이면세계를 사람이 살 수 있는 곳으로 만들기 위해, 그 어떤 나라보다도 많은 투자를 하고 있으니까요.","JPN":"北方合意体の技術力のおかげです。裏世界を人が住めるようにするため、どの国よりもたくさん投資していますから。","ENG":"It's all thanks to the technological prowess of the Northern Union. It invests more than any other nation to make the Counterside habitable for humans.","TWN":"這要歸功於北方和議會的技術。為了使異界成為人人可以居住的地方，我們投入的資金比其他任何國家都多。"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIOR_FLOOR_RESEARCH_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SOLDIOR_FLOOR_RESEARCH_NULL","text":{"KOREA":"박사님께서 고문으로 지원해주신 프로젝트도 마찬가지입니다. 프로젝트 셰퍼드는 침식체에게 고통받는 인류의 고충을 덜기 위해 시작된 것이죠.","JPN":"博士が顧問として参加してくださったプロジェクトもそうです。プロジェクト・シェパードは侵食体により苦しむ人類の苦情を減らすために始まったことでしたね。","ENG":"Same goes for the funding of the project you applied to be a consultant on. Project Shepherd was started to alleviate the suffering of humanity from C.O.s.","TWN":"你作為顧問所支援的項目也是如此。牧羊人計畫啟動的目的，就是為了減輕人類因侵蝕體所帶來的痛苦。"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIOR_FLOOR_RESEARCH_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"프로젝트의 전반에 대한 설명은 전해 들었습니다.","JPN":"プロジェクト全般についての説明は聞きました。","ENG":"I was informed about the overall project.","TWN":"我已經收到了關於整個專案的詳細介紹。"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":null,"C":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"하지만 기밀유지서약에 사인할 때까지도 연구소가 이면세계에 있는 줄은 몰랐어요.","JPN":"ですが、秘密保持誓約書にサインした時でさえ研究所が裏世界にあるとは思いませんでした。","ENG":"But I didn't know the lab was in the Counterside until I signed the NDA.","TWN":"但在簽署保密協定之前，我並不知道研究所位於異界之中。"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":null,"C":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"굳이 시설을 이런 곳에 세운 이유가 있는 겁니까?","JPN":"わざわざ施設をこんなところに建てたのは何か理由があるのですか？","ENG":"Is there a reason for building the lab in a place like this?","TWN":"有什麼理由一定要在這種地方建造設施嗎？"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":null,"C":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOLDIOR_FLOOR_RESEARCH_NULL","text":{"KOREA":"차차 알게 되시겠지만, 간단히 설명을 드리자면…","JPN":"そのうちおわかりになると思いますが、簡単にご説明しますと……","ENG":"You'll know soon enough, but to briefly explain...","TWN":"你慢慢會了解的，不過簡單來說……"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":null,"C":{"char_id":"SOLDIOR_FLOOR_RESEARCH_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOLDIOR_FLOOR_RESEARCH_NULL","text":{"KOREA":"저희가 이 프로젝트에서 찾고자 하는 힘의 원류가 이곳에 있기 때문입니다.","JPN":"私たちがこのプロジェクトで調査している力の源がここにあるからです。","ENG":"the power source we are trying to find with this project lies here.","TWN":"因為這裡有我們這個項目所必需的能量源。"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":null,"C":{"char_id":"SOLDIOR_FLOOR_RESEARCH_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"이면세계에 침식체를 통제할 힘이 있다고요?","JPN":"裏世界に侵食体をコントロールする力があるというのですか？","ENG":"There is a way to control C.O.s in the Counterside?","TWN":"什麼？在異界發現了可以控制侵蝕體的力量？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOLDIOR_FLOOR_RESEARCH_NULL","text":{"KOREA":"저희는 이면세계에서 침식의 영향을 받지 않는 특별한 나무를 찾아냈습니다.","JPN":"私たちは裏世界で侵食にも影響されない特別な木を発見しました。","ENG":"We have found a special tree that is not affected by the Corruption in the Counterside.","TWN":"是的，在這裡，我們發現了一棵不受侵蝕影響的特殊樹木。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIOR_FLOOR_RESEARCH_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"이면세계에 그런 나무가 자라다니… 들어본 적도 없군요.","JPN":"裏世界でそんな木が生えてるなんて……初めて聞きました。","ENG":"A tree growing in the Counterside...? This is the first time hearing it for me.","TWN":"異界竟然會長出那樣的樹木……我從來沒聽說過。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIOR_FLOOR_RESEARCH_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SOLDIOR_FLOOR_RESEARCH_NULL","text":{"KOREA":"뿐만 아니라, 그 나무는 한 그루가 온전히 한 세계에만 존재하지 않습니다. 우리가 이곳에서 발견한 건 일부분일 뿐이죠.","JPN":"それだけではなく、その木は一つの世界だけに存在しているわけではありません。私たちがここで発見したのは、ごく一部なのです。","ENG":"Not just that. That tree doesn't exist entirely in just one world. The one we found is only a part of it.","TWN":"而且，那顆樹並不完全存在於一個世界中。我們在這裡發現的只是它其中的一部分。"},"stage":{"bg":"LABORATORY","slots":{"L":null,"C":{"char_id":"SOLDIOR_FLOOR_RESEARCH_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"하나가 아니라고요? 그게 어떤 의미죠?","JPN":"一本だけではない？　それはどういうことですか？","ENG":"What do you mean it's only a portion of it?","TWN":"不止一個？這表示什麼？"},"stage":{"bg":"LABORATORY","slots":{"L":null,"C":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SOLDIOR_FLOOR_RESEARCH_NULL","text":{"KOREA":"그 나무는 땅 속이 아닌 차원계면을 뚫고 자라 있어요. 마치 여러 차원을 넘나들면서 자라온 것처럼.","JPN":"その木は、地面ではなく次元界面を貫き抜けて生えています。まるで、いろんな次元を行き来しているように。","ENG":"That tree grew by digging its roots through the dimension surface and not the ground. It's as if it grew by crossing multiple dimensions.","TWN":"那棵樹不是紮根在地下，而是生長在次元介面當中。就像是跨越了多個次元。"},"stage":{"bg":"LABORATORY","slots":{"L":null,"C":{"char_id":"SOLDIOR_FLOOR_RESEARCH_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SOLDIOR_FLOOR_RESEARCH_NULL","text":{"KOREA":"저흰 그것을 청동나무로 명명하고 분석하기 시작했습니다.","JPN":"私たちはそれを青銅の木と名づけ、分析を始めました。","ENG":"We have named it the Bronze Tree and have started analyzing it.","TWN":"我們將它命名為青銅樹，並對它展開了分析。"},"stage":{"bg":"LABORATORY","slots":{"L":null,"C":{"char_id":"SOLDIOR_FLOOR_RESEARCH_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"그렇다면, 프로젝트 세퍼드도 그 청동나무와 연관이 있는 걸까요?","JPN":"なら、プロジェクト・シェパードもあの青銅の木と関係があるんですか？","ENG":"Then, this Bronze Tree has something to do with Project Shepherd?","TWN":"那麼，牧羊人計畫是否也與青銅樹有關呢？"},"stage":{"bg":"LABORATORY","slots":{"L":null,"C":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SOLDIOR_FLOOR_RESEARCH_NULL","text":{"KOREA":"맞습니다. 저희는 바로 그 청동나무로부터 침식에 저항하는 원리를 찾던 중 새로운 에너지를 관측했거든요.","JPN":"そのとおりです。私たちはその青銅の木から侵食に抵抗する原理を調べている途中、新しいエネルギーを観測したのですよ。","ENG":"Correct. While we were researching how the Bronze Tree was able to resist the Corruption, we discovered a new energy source.","TWN":"沒錯。我們在尋找青銅樹抵抗侵蝕的原理的同時，也在過程中觀測到了新能量的產生。"},"stage":{"bg":"LABORATORY","slots":{"L":null,"C":{"char_id":"SOLDIOR_FLOOR_RESEARCH_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SOLDIOR_FLOOR_RESEARCH_NULL","text":{"KOREA":"조사원들은 그 에너지를 침식체가 극도로 싫어한다는 걸 알게 됐죠.","JPN":"調査員は侵食体がそのエネルギーをとても嫌がってるということに気付きました。","ENG":"And the researchers found out that C.O.s strongly despise this energy.","TWN":"我們的調查人員發現，侵蝕體非常不喜歡這種能量。"},"stage":{"bg":"LABORATORY","slots":{"L":null,"C":{"char_id":"SOLDIOR_FLOOR_RESEARCH_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"들어본 적도 없군요. 침식체가 싫어하는 것도 있다니.","JPN":"初めて聞きましたね。侵食体が嫌うものがあるなんて。","ENG":"I've never heard of such a thing. So there are things that C.O.s hate too, huh?","TWN":"我第一次聽說。侵蝕體會有不喜歡的東西。"},"stage":{"bg":"LABORATORY","slots":{"L":null,"C":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"나무에겐 이면세계에서 살아남기 위한 일종의 방어기재 같은 걸까요?","JPN":"木からしたら、裏世界で生き残るためのある種の防衛機制のようなものなんでしょうか？","ENG":"Is this energy a defense mechanism for the tree to survive in the Counterside?","TWN":"這就像是樹木在異界生存的某種防禦機制？"},"stage":{"bg":"LABORATORY","slots":{"L":null,"C":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SOLDIOR_FLOOR_RESEARCH_NULL","text":{"KOREA":"그럴 지도 모르죠.","JPN":"そうかもしれません。","ENG":"Perhaps.","TWN":"也許是的。"},"stage":{"bg":"LABORATORY","slots":{"L":null,"C":{"char_id":"SOLDIOR_FLOOR_RESEARCH_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SOLDIOR_FLOOR_RESEARCH_NULL","text":{"KOREA":"저희는 그 에너지를 분석하는 과정에서 몇 가지 특성을 발견했습니다.","JPN":"私たちはそのエネルギーを分析する過程で、いくつかの特性を発見しました。","ENG":"During our analysis of the energy, we discovered some of its characteristics.","TWN":"在分析這種能量的過程中，我們發現了幾個特性。"},"stage":{"bg":"LABORATORY","slots":{"L":null,"C":{"char_id":"SOLDIOR_FLOOR_RESEARCH_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SOLDIOR_FLOOR_RESEARCH_NULL","text":{"KOREA":"그 일련의 특성은 박사님의 고국, 노르드나빅의 전승에서 다루던 존재를 닮아있더군요.","JPN":"その一連の特性は博士の母国、ノルドナビックで伝承された存在に似ていたのです。","ENG":"And also that its characteristics seem to resemble those written in the folklore of your home country, Nordnavik.","TWN":"這一系列特性，與博士你的國家，諾爾德萊比傳說中所涉及的存在非常相似。"},"stage":{"bg":"LABORATORY","slots":{"L":null,"C":{"char_id":"SOLDIOR_FLOOR_RESEARCH_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SOLDIOR_FLOOR_RESEARCH_NULL","text":{"KOREA":"정령.","JPN":"精霊。","ENG":"Elemental.","TWN":"精靈。"},"stage":{"bg":"LABORATORY","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":null,"text":{"KOREA":"노르드나빅의 전승 속 정령은 사람들을 멋대로 울고 웃게 하며 장난 치는 것을 즐기지.","JPN":"ノルドナビックの伝承に出てくる精霊は、人々を勝手に泣かせたり笑わせたりして遊ぶ。","ENG":"In Nordnavik folklore, Elementals are known for pranking humans and making them laugh or cry at will.","TWN":"在諾爾德萊比的傳說中，精靈喜歡隨心所欲地戲弄人類，是一種讓人又哭又笑的存在。"},"stage":{"bg":"LAB","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};